<?php ($cardPrice = $service->priceForCity($selectedCity ?? null)); ?>
<article class="service-card h-100">
    <a href="<?php echo e(route('services.show', $service)); ?>" class="service-image-link"><img src="<?php echo e($service->image_url); ?>" alt="<?php echo e($service->title); ?>" loading="lazy"><span class="service-category"><?php echo e($service->category->name ?? 'Party Service'); ?></span><?php if($service->discount_price): ?><span class="discount-badge">Popular deal</span><?php endif; ?></a>
    <?php if(auth()->guard()->check()): ?><form class="card-wishlist" method="post" action="<?php echo e(route('wishlist.store',$service)); ?>"><?php echo csrf_field(); ?><button type="submit" title="Save to wishlist" aria-label="Save <?php echo e($service->title); ?> to wishlist"><i class="fa-regular fa-heart"></i></button></form><?php endif; ?>
    <div class="service-body"><div class="card-meta"><span><i class="fa-solid fa-location-dot"></i> <?php echo e($selectedCity?->name ?? 'Delhi NCR'); ?></span><span class="rating"><i class="fa-solid fa-star"></i> <?php echo e($service->rating); ?> <small>(<?php echo e($service->total_reviews); ?>)</small></span></div><h3><a href="<?php echo e(route('services.show',$service)); ?>"><?php echo e($service->title); ?></a></h3><p><?php echo e(\Illuminate\Support\Str::limit($service->short_description,76)); ?></p><div class="service-facts"><span><i class="fa-regular fa-clock"></i> <?php echo e($service->duration); ?></span><?php if($service->age_group): ?><span><i class="fa-solid fa-child-reaching"></i> <?php echo e($service->age_group); ?></span><?php endif; ?></div><div class="service-footer"><div class="price-row"><small>Starting at</small><span>&#8377;<?php echo e(number_format($cardPrice)); ?></span><?php if($cardPrice < (float)$service->price): ?><del>&#8377;<?php echo e(number_format((float)$service->price)); ?></del><?php endif; ?></div><div class="service-card-actions"><form method="post" action="<?php echo e(route('cart.add')); ?>"><?php echo csrf_field(); ?><input type="hidden" name="service_id" value="<?php echo e($service->id); ?>"><input type="hidden" name="city_id" value="<?php echo e($selectedCity?->id); ?>"><button class="icon-link" title="Add to cart" aria-label="Add <?php echo e($service->title); ?> to cart"><i class="fa-solid fa-cart-plus"></i></button></form><a class="btn btn-party btn-sm" href="<?php echo e(route('booking.create',['service'=>$service->slug])); ?>">Book now</a></div></div></div>
</article>
